import { useMemo, useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { addVehicle } from "../../api/vehicleApi";

export default function AddVehicle() {
  const navigate = useNavigate();

  const [vehicle, setVehicle] = useState({
    brand: "",
    type: "",
    year: "",
    price: "",
    status: "available",
    vehicleNumber: "",
    details: "",
  });

  const [images, setImages] = useState([]); // File[]
  const previews = useMemo(() => images.map((f) => URL.createObjectURL(f)), [images]);

  useEffect(() => {
    return () => previews.forEach((u) => URL.revokeObjectURL(u));
  }, [previews]);

  const [saving, setSaving] = useState(false);

  const vehicleTypes = ["SUV", "Sedan", "Hatchback", "Truck", "Van", "Coupe"];
  const statuses = ["available", "reserved", "sold"];

  const handleChange = (e) => {
    const { name, value } = e.target;
    setVehicle((prev) => ({ ...prev, [name]: value }));
  };

  const onPickImages = (e) => {
    const files = Array.from(e.target.files || []).slice(0, 4);
    setImages(files);
    e.target.value = "";
  };

  const removeImage = (idx) => {
    setImages((prev) => prev.filter((_, i) => i !== idx));
  };

  const submit = async (e) => {
    e.preventDefault();

    const currentYear = new Date().getFullYear();
    const yearNum = Number(vehicle.year);
    const priceNum = Number(vehicle.price);

    if (!vehicle.brand.trim()) return alert("Brand is required");
    if (!vehicle.type) return alert("Vehicle type is required");
    if (!vehicle.year) return alert("Year is required");
    if (Number.isNaN(yearNum)) return alert("Year must be a number");
    if (yearNum > currentYear) return alert(`Year cannot be in the future (max ${currentYear})`);
    if (yearNum < 1900) return alert("Year must be >= 1900");

    if (!vehicle.price) return alert("Price is required");
    if (Number.isNaN(priceNum) || priceNum < 0) return alert("Price must be >= 0");

    const fd = new FormData();
    fd.append("brand", vehicle.brand.trim());
    fd.append("type", vehicle.type);
    fd.append("year", String(yearNum));
    fd.append("price", String(priceNum));
    fd.append("status", vehicle.status);
    fd.append("vehicleNumber", vehicle.vehicleNumber.trim());
    fd.append("details", vehicle.details.trim());

    images.forEach((file) => fd.append("images", file));

    try {
      setSaving(true);
      await addVehicle(fd);
      alert("Vehicle added successfully");
      navigate("/vehicles");
    } catch (err) {
      alert(err.response?.data?.message || "Error adding vehicle");
    } finally {
      setSaving(false);
    }
  };

  return (
    <div style={{ backgroundColor: "var(--bg)", paddingBottom: "40px", minHeight: "100vh" }}>
      {/* Page Header */}
      <div style={{
        paddingBottom: "40px",
        borderBottom: "1px solid var(--border)",
        marginBottom: "40px"
      }}>
        <h1 style={{
          fontSize: "32px",
          fontWeight: 800,
          color: "var(--text)",
          margin: "0 0 8px 0",
          letterSpacing: "-0.5px"
        }}>
          Add New Vehicle
        </h1>
        <p style={{
          fontSize: "15px",
          color: "var(--text-muted)",
          margin: 0,
          fontWeight: 300
        }}>
          Expand your inventory with a new vehicle listing
        </p>
      </div>

      {/* Form Container */}
      <div style={{
        maxWidth: "900px",
        margin: "0 auto",
        padding: "0 20px"
      }}>
        <div style={{
          backgroundColor: "var(--bg-card)",
          borderRadius: "12px",
          border: "1px solid var(--border)",
          padding: "32px",
          boxShadow: "0 4px 12px rgba(0,0,0,0.05)"
        }}>
          <form onSubmit={submit} style={{ display: "flex", flexDirection: "column", gap: "24px" }}>

            {/* Basic Info Section */}
            <div>
              <div style={{
                fontSize: "14px",
                fontWeight: 700,
                color: "var(--text)",
                marginBottom: "16px",
                textTransform: "uppercase",
                letterSpacing: "0.4px"
              }}>
                Basic Information
              </div>

              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16, marginBottom: 16 }}>
                <div>
                  <label style={{
                    display: "block",
                    fontSize: "14px",
                    fontWeight: 600,
                    color: "var(--text)",
                    marginBottom: "8px",
                    letterSpacing: "-0.2px"
                  }}>
                    Brand <span style={{ color: "var(--primary)" }}>*</span>
                  </label>
                  <input
                    name="brand"
                    placeholder="Vehicle Brand"
                    value={vehicle.brand}
                    onChange={handleChange}
                    required
                    style={{
                      width: "100%",
                      padding: "10px 14px",
                      fontSize: "14px",
                      border: "1px solid var(--border)",
                      borderRadius: "8px",
                      backgroundColor: "var(--bg)",
                      color: "var(--text)",
                      boxSizing: "border-box",
                      transition: "all 0.2s",
                      outline: "none"
                    }}
                    onFocus={(e) => {
                      e.currentTarget.style.borderColor = "var(--primary)";
                      e.currentTarget.style.boxShadow = "0 0 0 3px var(--primary-soft)";
                    }}
                    onBlur={(e) => {
                      e.currentTarget.style.borderColor = "var(--border)";
                      e.currentTarget.style.boxShadow = "none";
                    }}
                  />
                </div>

                <div>
                  <label style={{
                    display: "block",
                    fontSize: "14px",
                    fontWeight: 600,
                    color: "var(--text)",
                    marginBottom: "8px",
                    letterSpacing: "-0.2px"
                  }}>
                    Type <span style={{ color: "var(--primary)" }}>*</span>
                  </label>
                  <select
                    name="type"
                    value={vehicle.type}
                    onChange={handleChange}
                    required
                    style={{
                      width: "100%",
                      padding: "10px 14px",
                      fontSize: "14px",
                      border: "1px solid var(--border)",
                      borderRadius: "8px",
                      backgroundColor: "var(--bg)",
                      color: "var(--text)",
                      boxSizing: "border-box",
                      cursor: "pointer",
                      transition: "all 0.2s",
                      outline: "none"
                    }}
                    onFocus={(e) => {
                      e.currentTarget.style.borderColor = "var(--primary)";
                      e.currentTarget.style.boxShadow = "0 0 0 3px var(--primary-soft)";
                    }}
                    onBlur={(e) => {
                      e.currentTarget.style.borderColor = "var(--border)";
                      e.currentTarget.style.boxShadow = "none";
                    }}
                  >
                    <option value="">Select Type</option>
                    {vehicleTypes.map((t) => <option key={t} value={t}>{t}</option>)}
                  </select>
                </div>
              </div>

              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16, marginBottom: 16 }}>
                <div>
                  <label style={{
                    display: "block",
                    fontSize: "14px",
                    fontWeight: 600,
                    color: "var(--text)",
                    marginBottom: "8px",
                    letterSpacing: "-0.2px"
                  }}>
                    Year <span style={{ color: "var(--primary)" }}>*</span>
                  </label>
                  <input
                    name="year"
                    type="number"
                    placeholder="Year"
                    value={vehicle.year}
                    onChange={handleChange}
                    required
                    style={{
                      width: "100%",
                      padding: "10px 14px",
                      fontSize: "14px",
                      border: "1px solid var(--border)",
                      borderRadius: "8px",
                      backgroundColor: "var(--bg)",
                      color: "var(--text)",
                      boxSizing: "border-box",
                      transition: "all 0.2s",
                      outline: "none"
                    }}
                    onFocus={(e) => {
                      e.currentTarget.style.borderColor = "var(--primary)";
                      e.currentTarget.style.boxShadow = "0 0 0 3px var(--primary-soft)";
                    }}
                    onBlur={(e) => {
                      e.currentTarget.style.borderColor = "var(--border)";
                      e.currentTarget.style.boxShadow = "none";
                    }}
                  />
                </div>

                <div>
                  <label style={{
                    display: "block",
                    fontSize: "14px",
                    fontWeight: 600,
                    color: "var(--text)",
                    marginBottom: "8px",
                    letterSpacing: "-0.2px"
                  }}>
                    Price (LKR) <span style={{ color: "var(--primary)" }}>*</span>
                  </label>
                  <input
                    name="price"
                    type="number"
                    placeholder="Price"
                    value={vehicle.price}
                    onChange={handleChange}
                    required
                    style={{
                      width: "100%",
                      padding: "10px 14px",
                      fontSize: "14px",
                      border: "1px solid var(--border)",
                      borderRadius: "8px",
                      backgroundColor: "var(--bg)",
                      color: "var(--text)",
                      boxSizing: "border-box",
                      transition: "all 0.2s",
                      outline: "none"
                    }}
                    onFocus={(e) => {
                      e.currentTarget.style.borderColor = "var(--primary)";
                      e.currentTarget.style.boxShadow = "0 0 0 3px var(--primary-soft)";
                    }}
                    onBlur={(e) => {
                      e.currentTarget.style.borderColor = "var(--border)";
                      e.currentTarget.style.boxShadow = "none";
                    }}
                  />
                </div>
              </div>
            </div>

            {/* Status & Registration */}
            <div>
              <div style={{
                fontSize: "14px",
                fontWeight: 700,
                color: "var(--text)",
                marginBottom: "16px",
                textTransform: "uppercase",
                letterSpacing: "0.4px"
              }}>
                Status & Registration
              </div>

              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16, marginBottom: 16 }}>
                <div>
                  <label style={{
                    display: "block",
                    fontSize: "14px",
                    fontWeight: 600,
                    color: "var(--text)",
                    marginBottom: "8px",
                    letterSpacing: "-0.2px"
                  }}>
                    Status
                  </label>
                  <select
                    name="status"
                    value={vehicle.status}
                    onChange={handleChange}
                    style={{
                      width: "100%",
                      padding: "10px 14px",
                      fontSize: "14px",
                      border: "1px solid var(--border)",
                      borderRadius: "8px",
                      backgroundColor: "var(--bg)",
                      color: "var(--text)",
                      boxSizing: "border-box",
                      cursor: "pointer",
                      transition: "all 0.2s",
                      outline: "none"
                    }}
                    onFocus={(e) => {
                      e.currentTarget.style.borderColor = "var(--primary)";
                      e.currentTarget.style.boxShadow = "0 0 0 3px var(--primary-soft)";
                    }}
                    onBlur={(e) => {
                      e.currentTarget.style.borderColor = "var(--border)";
                      e.currentTarget.style.boxShadow = "none";
                    }}
                  >
                    {statuses.map((s) => <option key={s} value={s}>{s.charAt(0).toUpperCase() + s.slice(1)}</option>)}
                  </select>
                </div>

                <div>
                  <label style={{
                    display: "block",
                    fontSize: "14px",
                    fontWeight: 600,
                    color: "var(--text)",
                    marginBottom: "8px",
                    letterSpacing: "-0.2px"
                  }}>
                    Vehicle Number/Registration
                  </label>
                  <input
                    name="vehicleNumber"
                    placeholder="e.g., CAB-1234"
                    value={vehicle.vehicleNumber}
                    onChange={handleChange}
                    style={{
                      width: "100%",
                      padding: "10px 14px",
                      fontSize: "14px",
                      border: "1px solid var(--border)",
                      borderRadius: "8px",
                      backgroundColor: "var(--bg)",
                      color: "var(--text)",
                      boxSizing: "border-box",
                      transition: "all 0.2s",
                      outline: "none"
                    }}
                    onFocus={(e) => {
                      e.currentTarget.style.borderColor = "var(--primary)";
                      e.currentTarget.style.boxShadow = "0 0 0 3px var(--primary-soft)";
                    }}
                    onBlur={(e) => {
                      e.currentTarget.style.borderColor = "var(--border)";
                      e.currentTarget.style.boxShadow = "none";
                    }}
                  />
                </div>
              </div>
            </div>

            {/* Details Section */}
            <div>
              <label style={{
                display: "block",
                fontSize: "14px",
                fontWeight: 600,
                color: "var(--text)",
                marginBottom: "8px",
                letterSpacing: "-0.2px"
              }}>
                Additional Details
              </label>
              <textarea
                name="details"
                rows={4}
                placeholder="Describe additional features, condition, maintenance history, etc."
                value={vehicle.details}
                onChange={handleChange}
                style={{
                  width: "100%",
                  padding: "10px 14px",
                  fontSize: "14px",
                  border: "1px solid var(--border)",
                  borderRadius: "8px",
                  backgroundColor: "var(--bg)",
                  color: "var(--text)",
                  boxSizing: "border-box",
                  fontFamily: "inherit",
                  transition: "all 0.2s",
                  outline: "none",
                  resize: "vertical"
                }}
                onFocus={(e) => {
                  e.currentTarget.style.borderColor = "var(--primary)";
                  e.currentTarget.style.boxShadow = "0 0 0 3px var(--primary-soft)";
                }}
                onBlur={(e) => {
                  e.currentTarget.style.borderColor = "var(--border)";
                  e.currentTarget.style.boxShadow = "none";
                }}
              />
            </div>

            {/* Image Upload */}
            <div>
              <label style={{
                display: "block",
                fontSize: "14px",
                fontWeight: 600,
                color: "var(--text)",
                marginBottom: "12px",
                letterSpacing: "-0.2px"
              }}>
                Vehicle Photos (up to 4 images)
              </label>
              <div style={{
                border: "2px dashed var(--border)",
                borderRadius: "8px",
                padding: "24px",
                textAlign: "center",
                backgroundColor: "var(--bg)",
                cursor: "pointer",
                transition: "all 0.2s"
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.borderColor = "var(--primary)";
                e.currentTarget.style.backgroundColor = "var(--primary-soft)";
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.borderColor = "var(--border)";
                e.currentTarget.style.backgroundColor = "var(--bg)";
              }}>
                <input
                  type="file"
                  accept="image/*"
                  multiple
                  onChange={onPickImages}
                  style={{ display: "none" }}
                  id="imageInput"
                />
                <label htmlFor="imageInput" style={{
                  display: "flex",
                  flexDirection: "column",
                  alignItems: "center",
                  cursor: "pointer",
                  gap: "8px"
                }}>
                  <div style={{ fontSize: "28px" }}>📸</div>
                  <div style={{
                    fontSize: "14px",
                    fontWeight: 600,
                    color: "var(--text)"
                  }}>
                    Click to upload photos
                  </div>
                  <div style={{
                    fontSize: "12px",
                    color: "var(--text-muted)"
                  }}>
                    PNG, JPG, GIF up to 10MB each
                  </div>
                </label>
              </div>

              {/* Image Previews */}
              {previews.length > 0 && (
                <div style={{ marginTop: "20px" }}>
                  <div style={{
                    fontSize: "12px",
                    fontWeight: 600,
                    color: "var(--text-muted)",
                    marginBottom: "12px",
                    textTransform: "uppercase",
                    letterSpacing: "0.3px"
                  }}>
                    {previews.length} image{previews.length !== 1 ? 's' : ''} selected
                  </div>
                  <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(160px, 1fr))", gap: 12 }}>
                    {previews.map((src, idx) => (
                      <div key={src} style={{
                        position: "relative",
                        borderRadius: "8px",
                        overflow: "hidden",
                        border: "1px solid var(--border)",
                        backgroundColor: "var(--bg)"
                      }}>
                        <div style={{
                          width: "100%",
                          aspectRatio: "4 / 3",
                          overflow: "hidden"
                        }}>
                          <img src={src} alt="preview" style={{
                            width: "100%",
                            height: "100%",
                            objectFit: "cover"
                          }} />
                        </div>
                        <button
                          type="button"
                          onClick={() => removeImage(idx)}
                          style={{
                            position: "absolute",
                            top: "8px",
                            right: "8px",
                            width: "28px",
                            height: "28px",
                            borderRadius: "50%",
                            backgroundColor: "#ee4c47",
                            color: "white",
                            border: "none",
                            fontSize: "14px",
                            fontWeight: 700,
                            cursor: "pointer",
                            transition: "all 0.2s",
                            display: "flex",
                            alignItems: "center",
                            justifyContent: "center"
                          }}
                          onMouseEnter={(e) => {
                            e.currentTarget.style.transform = "scale(1.1)";
                            e.currentTarget.style.boxShadow = "0 4px 12px rgba(238, 76, 71, 0.3)";
                          }}
                          onMouseLeave={(e) => {
                            e.currentTarget.style.transform = "scale(1)";
                            e.currentTarget.style.boxShadow = "none";
                          }}
                        >
                          ✕
                        </button>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>

            {/* Action Buttons */}
            <div style={{
              display: "flex",
              gap: "12px",
              paddingTop: "24px",
              borderTop: "1px solid var(--border)"
            }}>
              <button
                type="submit"
                disabled={saving}
                style={{
                  flex: 1,
                  padding: "12px 24px",
                  fontSize: "14px",
                  fontWeight: 700,
                  backgroundColor: "var(--primary)",
                  color: "white",
                  border: "none",
                  borderRadius: "8px",
                  cursor: saving ? "not-allowed" : "pointer",
                  transition: "all 0.2s",
                  letterSpacing: "0.3px",
                  opacity: saving ? 0.6 : 1
                }}
                onMouseEnter={(e) => !saving && (e.currentTarget.style.boxShadow = "0 6px 16px rgba(76, 175, 80, 0.3)")}
                onMouseLeave={(e) => !saving && (e.currentTarget.style.boxShadow = "none")}
              >
                {saving ? "Saving..." : "Save Vehicle"}
              </button>

              <button
                type="button"
                onClick={() => navigate("/vehicles")}
                style={{
                  padding: "12px 24px",
                  fontSize: "14px",
                  fontWeight: 600,
                  backgroundColor: "var(--bg)",
                  color: "var(--text)",
                  border: "1px solid var(--border)",
                  borderRadius: "8px",
                  cursor: "pointer",
                  transition: "all 0.2s",
                  letterSpacing: "0.2px"
                }}
                onMouseEnter={(e) => {
                  e.currentTarget.style.backgroundColor = "var(--bg-hover)";
                  e.currentTarget.style.borderColor = "var(--primary)";
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.backgroundColor = "var(--bg)";
                  e.currentTarget.style.borderColor = "var(--border)";
                }}
              >
                Cancel
              </button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
}
